from __future__ import annotations

from typing import Any

try:
    import numpy as np
except ModuleNotFoundError:  # pragma: no cover
    np = None  # type: ignore[assignment]

try:
    import librosa
except ModuleNotFoundError:  # pragma: no cover
    librosa = None  # type: ignore[assignment]

try:
    from scipy.signal import butter, filtfilt, lfilter
except ModuleNotFoundError:  # pragma: no cover
    butter = filtfilt = lfilter = None  # type: ignore[assignment]


class AugmentationError(RuntimeError):
    """Raised when an augmentation request cannot be completed."""


class DependencyUnavailableError(AugmentationError):
    """Raised when the audio augmentation stack is not installed."""


def _require_audio_stack() -> None:
    missing = []
    if np is None:
        missing.append("numpy")
    if librosa is None:
        missing.append("librosa")
    if butter is None or filtfilt is None or lfilter is None:
        missing.append("scipy")
    if missing:
        joined = ", ".join(missing)
        raise DependencyUnavailableError(
            f"Audio augmentation dependencies are missing: {joined}. "
            "Install backend/requirements.txt in a Python 3.11 or 3.12 environment."
        )


def _as_float32(audio: Any) -> "np.ndarray":
    _require_audio_stack()
    arr = np.asarray(audio, dtype=np.float32)
    if arr.ndim != 1:
        arr = np.ravel(arr)
    return arr


def _normalize(audio: Any) -> "np.ndarray":
    arr = _as_float32(audio)
    peak = float(np.max(np.abs(arr))) if arr.size else 0.0
    if peak > 0:
        arr = arr / max(1.0, peak)
    return arr.astype(np.float32)


