def add_background_noise(
    audio: Any,
    sr: int,
    *,
    snr_db: float = 10.0,
    noise_type: str = "office",
) -> "np.ndarray":
    """Mix synthetic ambient noise at the requested SNR."""
    _require_audio_stack()
    source = _normalize(audio)
    noise = _generate_ambient_noise(source.shape[0], sr, noise_type=noise_type)
    signal_power = float(np.mean(source**2)) + 1e-10
    noise_power = float(np.mean(noise**2)) + 1e-10
    desired_noise_power = signal_power / (10 ** (snr_db / 10.0))
    scale = float(np.sqrt(desired_noise_power / noise_power))
    mixed = source + noise * scale
    return _normalize(mixed)


def simulate_phone(audio: Any, sr: int) -> "np.ndarray":
    """Band-limit the signal to telephone speech bandwidth."""
    _require_audio_stack()
    source = _normalize(audio)
    band_limited = _butter_filter(source, sr, low_hz=300.0, high_hz=3400.0, order=5)
    if lfilter is not None:
        band_limited = lfilter([1.0, -0.92], [1.0], band_limited).astype(np.float32)
    return _normalize(band_limited)


def apply_augmentation(audio: Any, sr: int, augmentation_type: str, **kwargs: Any) -> tuple["np.ndarray", dict[str, Any]]:
    key = (augmentation_type or "clean").strip().lower().replace("-", "_").replace(" ", "_")

    if key in {"clean", "none"}:
        return _normalize(audio), {
            "type": "clean",
            "label": "Clean",
            "description": "No augmentation applied.",
        }

    if key in {"cold", "simulate_cold", "cold_sore_throat"}:
