        }

    if key in {"noise", "add_noise", "background_noise"}:
        snr_db = float(kwargs.get("snr_db", 10.0))
        noise_type = str(kwargs.get("noise_type", "office"))
        return add_background_noise(audio, sr, snr_db=snr_db, noise_type=noise_type), {
