            "snr_db": snr_db,
            "noise_type": noise_type,
        }

    if key in {"phone", "simulate_phone", "phone_call_quality"}:
        return simulate_phone(audio, sr), {
            "type": "phone",
            "label": "Simulate Phone Call Quality",
            "description": "Telephony-style 300-3400 Hz bandpass filtering.",
        }

    supported = ", ".join(sorted(available_augmentations().keys()))
    raise AugmentationError(f"Unknown augmentation '{augmentation_type}'. Supported types: {supported}.")


